mapper.sql:
WHERE 1 = 1
AND user_logs.id < #{lastUserLogId}
AND user_logs.created >= TO_DATE(#{dateFrom}, 'YYYY-MM-DD')
AND user_logs.created < (TO_DATE(#{dateTo}, 'YYYY-MM-DD') + INTERVAL '1 day')
AND user_logs.user_id = #{userNameId}
AND ( COALESCE(user_logs.type, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(user_logs.remote_addr, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(user_logs.http_user_agent, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(u.username, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(u.first_name, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(u.last_name, '') ILIKE '%' || #{searchText} || '%' OR COALESCE(NULLIF(TRIM(CONCAT(COALESCE(u.first_name, ''), ' ', COALESCE(u.last_name, ''))), ''), '') ILIKE '%' || #{searchText} || '%' )

mapper.select:
SELECT



ORDER BY


        ${orderBy}


        user_logs.id DESC



    LIMIT #{rowsPerPage}
